from urllib.parse import unquote_plus

def parse_query(query: str) -> dict[str, str | list[str]]:
    result = {}
    if not query:
        return result

    for pair in query.split("&"):
        if "=" in pair:
            key, value = pair.split("=", 1)
        else:
            # Handle keys without values (e.g., "key" instead of "key=value")
            key, value = pair, ""

        decoded_key = unquote_plus(key)
        decoded_value = unquote_plus(value)

        if decoded_key in result:
            existing = result[decoded_key]
            if isinstance(existing, list):
                existing.append(decoded_value)
            else:
                result[decoded_key] = [existing, decoded_value]
        else:
            result[decoded_key] = decoded_value

    return result

